def pick_coins_backtrack(coin_probs, n):
    def backtrack(index, heads, tails):
        if heads + tails == n:
            return [index]
        if heads > n or tails > n - heads:
            return []
        result = []
        result += backtrack(index + 1, heads + 1, tails)
        result += backtrack(index + 1, heads, tails + 1)
        return result

    return backtrack(0, 0, 0)

